 declare(strict_types=1); namespace tapmeppe\composer\summons; use Symfony\Component\Console\Command\Command; use Symfony\Component\Console\Input\InputInterface; use Symfony\Component\Console\Output\OutputInterface; class Abcd extends \tapmeppe\composer\helpers\Summon { protected static $defaultName = 'governance:abcd'; protected function configure(): void { $this ->describe('This command is used to ping the CLI.'); } protected function execute(InputInterface $input, OutputInterface $output): int { $output->writeln('<info>[✓]</info> Job done!'); return Command::SUCCESS; } } 